const canvas = document.createElement('canvas');
canvas.width = 600; canvas.height = 440;
canvas.style.background = '#0a0a2e';
canvas.style.borderRadius = '12px';
canvas.style.cursor = 'pointer';
container.appendChild(canvas);
const ctx = canvas.getContext('2d');

const info = document.createElement('div');
info.style.cssText = 'color:#94a3b8;font-size:13px;margin-top:8px;padding:4px 8px;';
info.innerHTML = '🌳 Click any node to expand/collapse its sub-operators';
container.appendChild(info);

const nodes = {
  HARM: {x:300,y:40,color:'#ef4444',text:'"John harmed Bill"',children:['PROPEL','DAMAGE'],expanded:false},
  PROPEL: {x:180,y:140,color:'#f59e0b',text:'"John swung fist at Bill"',children:['MOVE_ARM','APPLY_FORCE'],expanded:false},
  DAMAGE: {x:420,y:140,color:'#f59e0b',text:'"Bill\'s nose broke"',children:['CONTACT','STATE_CHANGE'],expanded:false},
  MOVE_ARM: {x:100,y:240,color:'#22c55e',text:'"John\'s arm extended rapidly"',children:['MUSCLE','TRAJECTORY'],expanded:false},
  APPLY_FORCE: {x:240,y:240,color:'#22c55e',text:'"Force transferred to Bill\'s face"',children:[],expanded:false},
  CONTACT: {x:360,y:240,color:'#22c55e',text:'"Fist contacted nose"',children:[],expanded:false},
  STATE_CHANGE: {x:500,y:240,color:'#22c55e',text:'"nose: intact → broken"',children:[],expanded:false},
  MUSCLE: {x:60,y:340,color:'#3b82f6',text:'"Bicep contracted"',children:[],expanded:false},
  TRAJECTORY: {x:160,y:340,color:'#3b82f6',text:'"Arc toward face"',children:[],expanded:false}
};

function getVisible() {
  const vis = ['HARM'];
  const q = ['HARM'];
  while(q.length) {
    const id = q.shift();
    const n = nodes[id];
    if(n.expanded && n.children.length) {
      n.children.forEach(c => { vis.push(c); q.push(c); });
    }
  }
  return vis;
}

function draw() {
  ctx.clearRect(0,0,600,440);
  const vis = getVisible();
  // Draw edges
  vis.forEach(id => {
    const n = nodes[id];
    if(n.expanded) {
      n.children.forEach(cid => {
        if(vis.includes(cid)) {
          const c = nodes[cid];
          ctx.beginPath();
          ctx.moveTo(n.x, n.y+16);
          ctx.lineTo(c.x, c.y-16);
          ctx.strokeStyle = 'rgba(148,163,184,0.3)';
          ctx.lineWidth = 2;
          ctx.stroke();
        }
      });
    }
  });
  // Draw nodes
  vis.forEach(id => {
    const n = nodes[id];
    const hasKids = n.children.length > 0;
    ctx.beginPath();
    const w = ctx.measureText(id).width + 32;
    const rx = Math.max(w/2, 36);
    ctx.roundRect(n.x-rx, n.y-16, rx*2, 32, 8);
    ctx.fillStyle = n.expanded ? n.color+'33' : n.color+'22';
    ctx.strokeStyle = n.color;
    ctx.lineWidth = n.expanded ? 2 : 1;
    ctx.fill(); ctx.stroke();
    ctx.fillStyle = n.color;
    ctx.font = 'bold 13px system-ui';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(id, n.x, n.y);
    if(hasKids && !n.expanded) {
      ctx.fillStyle = '#64748b';
      ctx.font = '10px system-ui';
      ctx.fillText('+', n.x+rx-10, n.y);
    }
  });
}

canvas.onclick = (e) => {
  const rect = canvas.getBoundingClientRect();
  const mx = (e.clientX - rect.left) * (600/rect.width);
  const my = (e.clientY - rect.top) * (440/rect.height);
  const vis = getVisible();
  for(const id of vis) {
    const n = nodes[id];
    if(Math.abs(mx-n.x)<50 && Math.abs(my-n.y)<18) {
      if(n.children.length > 0) {
        n.expanded = !n.expanded;
        info.innerHTML = n.expanded ? '📖 <b>'+id+'</b>: '+n.text : '🌳 Click any node to expand/collapse';
      } else {
        info.innerHTML = '🍃 <b>'+id+'</b> (leaf): '+n.text;
      }
      draw();
      return;
    }
  }
};
draw();

const wrap = document.createElement('div');
wrap.style.cssText = 'font-family:system-ui;color:#e2e8f0;';
container.appendChild(wrap);

const steps = [
  { op: 'Initial State', entities: { John: {health:'healthy',location:'street',mood:'angry',holding:'nothing'}, Bill: {health:'healthy',location:'street',mood:'unaware',holding:'nothing'} }},
  { op: 'HARM (begin)', entities: { John: {health:'healthy',location:'street',mood:'angry',holding:'nothing'}, Bill: {health:'healthy',location:'street',mood:'unaware',holding:'nothing'} }, highlight: 'John.mood' },
  { op: 'PROPEL (swing fist)', entities: { John: {health:'healthy',location:'street',mood:'angry',holding:'fist-clenched'}, Bill: {health:'healthy',location:'street',mood:'alarmed',holding:'nothing'} }, highlight: 'John.holding,Bill.mood', changed: ['John.holding','Bill.mood'] },
  { op: 'CONTACT (fist hits nose)', entities: { John: {health:'healthy',location:'street',mood:'angry',holding:'fist-clenched'}, Bill: {health:'injured',location:'street',mood:'pain',holding:'nothing'} }, highlight: 'Bill.health,Bill.mood', changed: ['Bill.health','Bill.mood'] },
  { op: 'STATE_CHANGE (nose breaks)', entities: { John: {health:'healthy',location:'street',mood:'satisfied',holding:'nothing'}, Bill: {health:'nose-broken',location:'street',mood:'agony',holding:'nose'} }, highlight: 'Bill.health,John.mood,Bill.holding', changed: ['Bill.health','John.mood','Bill.holding','John.holding'] },
  { op: 'HARM (complete)', entities: { John: {health:'healthy',location:'fleeing',mood:'fearful',holding:'nothing'}, Bill: {health:'nose-broken',location:'street',mood:'agony',holding:'nose'} }, highlight: 'John.location,John.mood', changed: ['John.location','John.mood'] }
];

let step = 0;

function render() {
  wrap.innerHTML = '';
  const s = steps[step];
  const changedSet = new Set(s.changed || []);

  const header = document.createElement('div');
  header.style.cssText = 'display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;';
  header.innerHTML = `<span style="font-weight:700;color:#a78bfa;font-size:16px">Step ${step}: ${s.op}</span><span style="color:#64748b;font-size:13px">${step+1}/${steps.length}</span>`;
  wrap.appendChild(header);

  const grid = document.createElement('div');
  grid.style.cssText = 'display:grid;grid-template-columns:1fr 1fr;gap:12px;';

  for(const [name, attrs] of Object.entries(s.entities)) {
    const card = document.createElement('div');
    card.style.cssText = 'padding:14px;border-radius:10px;background:rgba(30,30,60,0.6);border:1px solid rgba(148,163,184,0.2);';
    card.innerHTML = `<div style="font-weight:700;font-size:15px;margin-bottom:8px">${name === 'John' ? '🤜' : '😵'} ${name}</div>`;
    for(const [k,v] of Object.entries(attrs)) {
      const isChanged = changedSet.has(name+'.'+k);
      const row = document.createElement('div');
      row.style.cssText = `display:flex;justify-content:space-between;padding:4px 8px;margin:2px 0;border-radius:4px;font-size:13px;${isChanged ? 'background:rgba(250,204,21,0.15);' : ''}`;
      row.innerHTML = `<span style="color:#94a3b8">${k}</span><span style="color:${isChanged ? '#fbbf24' : '#e2e8f0'};font-weight:${isChanged ? '700' : '400'}">${v}${isChanged ? ' ⬅' : ''}</span>`;
      card.appendChild(row);
    }
    grid.appendChild(card);
  }
  wrap.appendChild(grid);

  const controls = document.createElement('div');
  controls.style.cssText = 'display:flex;gap:8px;margin-top:12px;justify-content:center;';
  const prev = document.createElement('button');
  prev.textContent = '← Previous';
  prev.style.cssText = 'padding:8px 16px;border-radius:8px;background:#374151;color:white;border:none;cursor:pointer;font-weight:600;opacity:'+(step>0?'1':'0.4');
  prev.onclick = () => { if(step>0){step--;render();} };
  const next = document.createElement('button');
  next.textContent = 'Next →';
  next.style.cssText = 'padding:8px 16px;border-radius:8px;background:#7c3aed;color:white;border:none;cursor:pointer;font-weight:600;opacity:'+(step<steps.length-1?'1':'0.4');
  next.onclick = () => { if(step<steps.length-1){step++;render();} };
  controls.appendChild(prev); controls.appendChild(next);
  wrap.appendChild(controls);

  const note = document.createElement('div');
  note.style.cssText = 'color:#64748b;font-size:12px;margin-top:8px;text-align:center;';
  note.textContent = 'Yellow highlights show state changes from the current operator. This is what NEKG tracks.';
  wrap.appendChild(note);
}
render();

const wrap = document.createElement('div');
wrap.style.cssText = 'font-family:system-ui;color:#e2e8f0;display:grid;gap:10px;';
container.appendChild(wrap);

const stages = [
  {name:'1. Set Endpoints',icon:'🎯',color:'#ef4444',desc:'Define start state ("John is healthy, Bill is healthy") and end state ("John is fleeing, Bill has broken nose"). These are NEKG snapshots.'},
  {name:'2. Choose Root Operator',icon:'🌳',color:'#f59e0b',desc:'Select the high-level operator that transforms start→end. Here: HARM(John, Bill). This is the Level 0 midpoint.'},
  {name:'3. Recursive Decomposition',icon:'🔀',color:'#22c55e',desc:'HARM decomposes into sub-operators (PROPEL, DAMAGE). Each sub-operator decomposes further. This builds the tree — done in parallel at each level via midpoint diffusion.'},
  {name:'4. NEKG Validation',icon:'✅',color:'#3b82f6',desc:'At each tree node, check preconditions against NEKG. If PROPEL requires John near Bill but NEKG says they\'re apart, insert PTRANS(John→Bill) first. Consistency by construction.'},
  {name:'5. Leaf → Prose',icon:'✍️',color:'#a855f7',desc:'Leaf operators generate actual text. MOVE_ARM → "John\'s fist shot forward." Sequential left-to-right for flow, but the PLAN was parallel and hierarchical.'}
];

stages.forEach(s => {
  const card = document.createElement('div');
  card.style.cssText = `padding:14px;border-radius:10px;background:rgba(30,30,60,0.6);border-left:4px solid ${s.color};cursor:pointer;transition:all 0.2s;`;
  card.innerHTML = `<div style="display:flex;justify-content:space-between;align-items:center"><span style="font-weight:700;color:${s.color}">${s.icon} ${s.name}</span><span style="color:#64748b;font-size:11px">click</span></div><div class="desc" style="display:none;margin-top:8px;font-size:13px;color:#cbd5e1;line-height:1.6">${s.desc}</div>`;
  card.onclick = () => { const d=card.querySelector('.desc'); d.style.display=d.style.display==='none'?'block':'none'; };
  wrap.appendChild(card);
});
